// ==================================================
// NÓ 2: CLASSIFICAR CATEGORIA E SELECIONAR LOJAS
// ==================================================

const input = $input.first().json;
const produto = (input.body?.produto || input.produto || '').toLowerCase();
const lojasInput = (input.body?.lojas || input.lojas || 'auto').toString().toLowerCase();

// Tabela de categorias → lojas
const categorias = {
  eletro_grande: {
    palavras: ['ar-condicionado', 'ar condicionado', 'geladeira', 'refrigerador', 'fogão', 'fogao', 'máquina de lavar', 'maquina de lavar', 'lava e seca', 'freezer', 'microondas', 'forno'],
    lojas: ['google_shopping', 'mercadolivre', 'amazon', 'magalu', 'casas_bahia', 'ponto']
  },
  eletro_pequeno: {
    palavras: ['liquidificador', 'airfryer', 'air fryer', 'ferro de passar', 'cafeteira', 'batedeira', 'mixer', 'torradeira', 'aspirador', 'ventilador'],
    lojas: ['google_shopping', 'mercadolivre', 'amazon', 'shopee', 'magalu', 'casas_bahia']
  },
  eletronicos: {
    palavras: ['celular', 'smartphone', 'notebook', 'laptop', 'tablet', 'tv', 'televisão', 'televisao', 'monitor', 'fone', 'headset', 'caixa de som', 'mouse', 'teclado'],
    lojas: ['google_shopping', 'mercadolivre', 'amazon', 'magalu', 'casas_bahia', 'ponto']
  },
  casa_cozinha: {
    palavras: ['toalha', 'lençol', 'lencol', 'travesseiro', 'panela', 'frigideira', 'jogo de cama', 'cortina', 'tapete', 'cobertor', 'edredom', 'prato', 'talher', 'copo'],
    lojas: ['mercadolivre', 'shopee', 'amazon']
  },
  moveis: {
    palavras: ['sofá', 'sofa', 'mesa', 'cadeira', 'estante', 'rack', 'guarda-roupa', 'guarda roupa', 'cama', 'colchão', 'colchao', 'escrivaninha'],
    lojas: ['google_shopping', 'mercadolivre', 'amazon', 'magalu', 'casas_bahia']
  },
  alimentos: {
    palavras: ['arroz', 'feijão', 'feijao', 'óleo', 'oleo', 'açúcar', 'acucar', 'farinha', 'leite', 'café', 'cafe', 'carne', 'alimento'],
    lojas: ['carrefour', 'extra', 'amazon']
  },
  escritorio: {
    palavras: ['papel', 'caneta', 'impressora', 'toner', 'cartucho', 'envelope', 'pasta', 'grampeador', 'caderno'],
    lojas: ['mercadolivre', 'shopee', 'amazon']
  },
  equipamento_medico: {
    palavras: ['otoscópio', 'otoscopio', 'esfigmomanômetro', 'esfigmomanometro', 'estetoscópio', 'estetoscopio', 'oxímetro', 'oximetro', 'EPI', 'luva', 'jaleco', 'bisturi', 'termômetro', 'termometro'],
    lojas: ['google_shopping', 'mercadolivre', 'amazon']
  }
};

// Detectar categoria
let categoriaDetectada = 'geral';
let lojasAtivas = ['google_shopping', 'mercadolivre', 'amazon'];

for (const [cat, config] of Object.entries(categorias)) {
  for (const palavra of config.palavras) {
    if (produto.includes(palavra)) {
      categoriaDetectada = cat;
      lojasAtivas = config.lojas;
      break;
    }
  }
  if (categoriaDetectada !== 'geral') break;
}

// Se usuario pediu "todas"
if (lojasInput === 'todas' || lojasInput === 'all') {
  lojasAtivas = ['google_shopping', 'mercadolivre', 'amazon', 'shopee', 'magalu', 'casas_bahia', 'americanas', 'ponto', 'carrefour', 'extra'];
}

// Se usuario especificou numeros
const mapaNumeros = {
  '1': 'mercadolivre', '2': 'amazon', '3': 'shopee',
  '4': 'magalu', '5': 'casas_bahia', '6': 'americanas',
  '7': 'ponto', '8': 'carrefour', '9': 'extra', '10': 'google_shopping'
};

if (/^[\d,\s]+$/.test(lojasInput)) {
  const nums = lojasInput.split(',').map(n => n.trim());
  lojasAtivas = nums.map(n => mapaNumeros[n]).filter(Boolean);
}

return [{
  json: {
    produto: input.body?.produto || input.produto || '',
    produto_busca: encodeURIComponent(input.body?.produto || input.produto || ''),
    categoria: categoriaDetectada,
    lojas: lojasAtivas,
    buscar_google_shopping: lojasAtivas.includes('google_shopping'),
    buscar_mercadolivre: lojasAtivas.includes('mercadolivre'),
    cep: '35065118',
    timestamp: new Date().toISOString()
  }
}];

// ==================================================
// NÓ 6: PADRONIZAR + ESTATÍSTICA + AMOSTRAGEM
// ==================================================

const items = $input.all();
const todosResultados = [];

// --- EXTRAIR RESULTADOS DO GOOGLE SHOPPING ---
for (const item of items) {
  const data = item.json;

  // SerpAPI Google Shopping
  if (data.body?.shopping_results) {
    for (const r of data.body.shopping_results) {
      todosResultados.push({
        nome: r.title || 'Sem nome',
        preco: r.extracted_price || 0,
        preco_texto: r.price || 'N/I',
        loja: r.source || 'Google Shopping',
        link: r.link || r.product_link || '#',
        imagem: r.thumbnail || '',
        avaliacao: r.rating || null,
        num_avaliacoes: r.reviews || 0,
        frete_texto: r.delivery || 'Ver na loja',
        frete_valor: 0,
        prazo: r.delivery || 'Ver na loja',
        disponivel: true,
        fonte: 'google_shopping',
        parcelamento: r.installments?.text || 'N/I'
      });
    }
  }

  // Mercado Livre API
  if (data.body?.results) {
    for (const r of data.body.results) {
      const freteGratis = r.shipping?.free_shipping || false;
      todosResultados.push({
        nome: r.title || 'Sem nome',
        preco: r.price || 0,
        preco_texto: `R$ ${(r.price || 0).toLocaleString('pt-BR', {minimumFractionDigits: 2})}`,
        loja: `Mercado Livre - ${r.seller?.nickname || 'Vendedor'}`,
        link: r.permalink || '#',
        imagem: r.thumbnail || '',
        avaliacao: r.reviews?.rating_average || null,
        num_avaliacoes: r.reviews?.total || 0,
        frete_texto: freteGratis ? 'Frete Grátis' : 'Ver na loja',
        frete_valor: freteGratis ? 0 : -1,
        prazo: r.shipping?.estimated_delivery_time?.text || 'Ver na loja',
        disponivel: r.available_quantity > 0,
        fonte: 'mercadolivre',
        parcelamento: r.installments ? `${r.installments.quantity}x R$ ${r.installments.amount?.toFixed(2)}` : 'N/I',
        condicao: r.condition === 'new' ? 'Novo' : 'Usado'
      });
    }
  }
}

// --- FILTRAR PREÇO VÁLIDO ---
const comPreco = todosResultados.filter(r => r.preco > 0);

if (comPreco.length === 0) {
  return [{ json: { erro: true, mensagem: 'Nenhum resultado encontrado', resultados: [], stats: {} } }];
}

// --- ESTATÍSTICAS ---
const precos = comPreco.map(r => r.preco).sort((a, b) => a - b);
const n = precos.length;

const soma = precos.reduce((a, b) => a + b, 0);
const media = soma / n;
const mediana = n % 2 === 0 ? (precos[n/2 - 1] + precos[n/2]) / 2 : precos[Math.floor(n/2)];

// Moda
const freq = {};
precos.forEach(p => {
  const rounded = Math.round(p / 10) * 10;
  freq[rounded] = (freq[rounded] || 0) + 1;
});
const moda = Number(Object.entries(freq).sort((a, b) => b[1] - a[1])[0][0]);

// Desvio padrão
const variancia = precos.reduce((acc, p) => acc + Math.pow(p - media, 2), 0) / n;
const desvioPadrao = Math.sqrt(variancia);

// --- AMOSTRAGEM INTELIGENTE ---
const LIMITE_TOTAL = 15;

let resultadosFinal;

if (n <= 20) {
  // Poucos resultados: traz todos
  resultadosFinal = comPreco;
} else {
  // Regra de Sturges para número de faixas
  const numFaixas = Math.round(1 + 3.322 * Math.log10(n));
  const precoMin = precos[0];
  const precoMax = precos[n - 1];
  const larguraFaixa = (precoMax - precoMin) / numFaixas;

  // Criar faixas
  const faixas = [];
  for (let i = 0; i < numFaixas; i++) {
    const inicio = precoMin + (i * larguraFaixa);
    const fim = i === numFaixas - 1 ? precoMax + 1 : precoMin + ((i + 1) * larguraFaixa);
    const produtosFaixa = comPreco.filter(r => r.preco >= inicio && r.preco < fim);
    faixas.push({
      inicio: Math.round(inicio * 100) / 100,
      fim: Math.round(fim * 100) / 100,
      produtos: produtosFaixa,
      quantidade: produtosFaixa.length,
      proporcao: produtosFaixa.length / n
    });
  }

  // Amostra proporcional
  resultadosFinal = [];
  for (const faixa of faixas) {
    if (faixa.produtos.length === 0) continue;

    let qtdAmostra = Math.max(1, Math.round(faixa.proporcao * LIMITE_TOTAL));

    // Ordenar por: melhor avaliação, depois menor preço
    const ordenados = faixa.produtos.sort((a, b) => {
      if (b.avaliacao !== a.avaliacao) return (b.avaliacao || 0) - (a.avaliacao || 0);
      return a.preco - b.preco;
    });

    // Pegar amostra: mais barato + melhor avaliação + frete mais barato
    const selecionados = new Set();

    // Mais barato da faixa
    const maisBarato = [...faixa.produtos].sort((a, b) => a.preco - b.preco)[0];
    selecionados.add(JSON.stringify(maisBarato));

    // Melhor avaliado
    const melhorAvaliado = [...faixa.produtos].sort((a, b) => (b.avaliacao || 0) - (a.avaliacao || 0))[0];
    selecionados.add(JSON.stringify(melhorAvaliado));

    // Completar com os próximos
    for (const p of ordenados) {
      if (selecionados.size >= qtdAmostra) break;
      selecionados.add(JSON.stringify(p));
    }

    for (const s of selecionados) {
      resultadosFinal.push(JSON.parse(s));
    }
  }
}

// --- CALCULAR VALOR TOTAL ---
for (const r of resultadosFinal) {
  if (r.frete_valor >= 0) {
    r.valor_total = r.preco + r.frete_valor;
    r.valor_total_texto = `R$ ${r.valor_total.toLocaleString('pt-BR', {minimumFractionDigits: 2})}`;
  } else {
    r.valor_total = r.preco;
    r.valor_total_texto = `R$ ${r.preco.toLocaleString('pt-BR', {minimumFractionDigits: 2})} + frete`;
  }
}

// Ordenar por valor total
resultadosFinal.sort((a, b) => a.valor_total - b.valor_total);

return [{
  json: {
    erro: false,
    produto_pesquisado: items[0]?.json?.produto || 'N/I',
    total_encontrado: n,
    total_exibido: resultadosFinal.length,
    stats: {
      media: Math.round(media * 100) / 100,
      mediana: Math.round(mediana * 100) / 100,
      moda: moda,
      desvio_padrao: Math.round(desvioPadrao * 100) / 100,
      menor_preco: precos[0],
      maior_preco: precos[n - 1]
    },
    resultados: resultadosFinal,
    cep: '35065118',
    data_pesquisa: new Date().toISOString()
  }
}];

// ==================================================
// NÓ 8: GERAR CSV PARA EXCEL
// ==================================================

const data = $input.first().json.dados;
if (data.erro) return [{ json: { csv: 'Nenhum resultado' } }];

const header = 'Nome;Preço;Parcelamento;Frete;Valor Total;Prazo;Loja;Avaliação;Link';
const linhas = data.resultados.map(r => {
  return [
    `"${r.nome.replace(/"/g, '""')}"`,
    r.preco_texto,
    r.parcelamento,
    r.frete_texto,
    r.valor_total_texto,
    r.prazo,
    `"${r.loja.replace(/"/g, '""')}"`,
    r.avaliacao ? `${r.avaliacao}/5` : 'N/I',
    r.link
  ].join(';');
});

const csv = [header, ...linhas].join('\n');

return [{ json: { csv, dados: data } }];
